import ReactDOM from 'react-dom';


function Home() {
    //const [moviesName , setData] = useState(["Kantara","Ramayana","Rocketry", "Dangal"]); 
    const moviesname = ["Kantara","Ramayana","Rocketry", "Dangal"];
    // function displayMovie(){      
    // setData(moviesName.map(moviename => { <li key={moviename}> {moviename} </li>  }))
    // }
    return ( 
        <>
            <h2>Welcome Movie World !</h2>
            <p>This are list of our movie :</p>
            {/* <h3><ol>{displayMovie()}</ol></h3>  */}
            <ol>
                {moviesname.map(name => <li key={name}>{name}</li>)}
            </ol>
            <ul>
                {display(moviesname)} 
            </ul>
            
        </>
     );
}

function display(moviearr) {
    const result = moviearr.map(name => <li key={ipl}>{name}</li>);   
    return  result; 
  }

export default Home;
